"""
Cat Duty Tracker — Track cat care and feeding turns

Setup:
  pip install -r requirements.txt
  cp env.example .env          # add your GROQ_API_KEY
  uvicorn main:app --reload
  open http://localhost:8000
"""
import os, sqlite3
from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
import httpx
from dotenv import load_dotenv

load_dotenv()
GROQ_API_KEY = os.getenv("GROQ_API_KEY", "")
DB_FILE      = os.getenv("DB_FILE", "/tmp/cat_duty_tracker.db")
SYSTEM_PROMPT = "You are a specialised AI tool: Cat Duty Tracker.\n\nYou are a knowledgeable advisor. Give specific, personalised advice based on what the user has shared.\n\nYour job: Monitor and manage cat litter and food levels to ensure a happy and healthy pet. Receive reminders and notifications when it's time to refill or clean the litter box and food bowl, and track whose turn it is to feed the cat.\n\nThe user will provide: Litter Box Status, Food Level, Cat Name, Current Feeder, List of Feeders. Use all of this information to personalise your response.\n\nQuality rules:\n- Be specific to what the user has actually provided \u2014 never give generic advice that ignores their inputs\n- Do not start with filler openers like Sure, Great, Certainly, or Of course\n- Do not explain what you are about to do \u2014 just do it\n- Do not add unnecessary disclaimers unless they are genuinely important\n- If the user's input is vague, make reasonable assumptions and state them briefly\n- Aim for depth over length \u2014 one specific, useful insight beats three generic ones\n\nFormat your response as a structured table where appropriate."

app = FastAPI(title="Cat Duty Tracker")
app.add_middleware(CORSMiddleware, allow_origins=["*"], allow_methods=["*"], allow_headers=["*"])


# ── Database ───────────────────────────────────────────────────────────────────

def get_db():
    conn = sqlite3.connect(DB_FILE)
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    with get_db() as conn:
        conn.execute("""
            CREATE TABLE IF NOT EXISTS queries (
                id     INTEGER PRIMARY KEY AUTOINCREMENT,
                prompt TEXT NOT NULL,
                result TEXT,
                ts     TEXT DEFAULT (datetime('now'))
            )
        """)
        conn.commit()

init_db()


